{"subject":"Economics",'year':2000,"question":"Production is the:",'options':['Creation of goods and services for utility','Purchase of goods','Consumption of goods','Distribution of goods'],'correctIndex':0,"explanation":"Production creates utility."},
{"subject":"Economics",'year':2001,"question":"The law of diminishing returns applies in the:",'options':['Short run','Long run','Both','Neither'],'correctIndex':0,"explanation":"Diminishing returns occurs when at least one input is fixed (short run)."},
{"subject":"Economics",'year':2002,"question":"In the long run, all factors of production are:",'options':['Variable','Fixed','Constant','Zero'],'correctIndex':0,"explanation":"Long run allows all inputs to adjust."},
{"subject":"Economics",'year':2003,"question":"Total product (TP) is:",'options':['Total output produced','Output per unit of input','Change in output from an additional input','Average output'],'correctIndex':0,"explanation":"TP is the overall quantity of output."},
{"subject":"Economics",'year':2004,"question":"Marginal product (MP) is:",'options':['Change in total product from one additional unit of input','Total product divided by input','Average product','Total product'],'correctIndex':0,"explanation":"MP = ΔTP / ΔL."},
{"subject":"Economics",'year':2005,"question":"Average product (AP) is:",'options':['Total product divided by the quantity of the variable input','Marginal product','Total product','Change in total product'],'correctIndex':0,"explanation":"AP = TP / L."},
{"subject":"Economics",'year':2006,"question":"The law of diminishing returns states that:",'options':['Adding more of a variable input to a fixed input will eventually yield diminishing marginal returns','Output always increases','Costs always decrease','Marginal product always increases'],'correctIndex':0,"explanation":"This is the classic definition."},
{"subject":"Economics",'year':2007,"question":"Fixed costs are:",'options':['Costs that do not vary with output','Costs that vary with output','Total costs','Marginal costs'],'correctIndex':0,"explanation":"Fixed costs are incurred even if output is zero."},
{"subject":"Economics",'year':2008,"question":"Variable costs are:",'options':['Costs that vary with output','Costs that do not vary with output','Total costs','Sunk costs'],'correctIndex':0,"explanation":"Variable costs change with production level."},
{"subject":"Economics",'year':2009,"question":"Total cost (TC) =:",'options':['Fixed cost + Variable cost','Fixed cost × Variable cost','Average cost × Variable cost','Average cost + Variable cost'],'correctIndex':0,"explanation":"TC = FC + VC."},
{"subject":"Economics",'year':2010,"question":"Average cost (AC) =:",'options':['TC / Q','FC / Q','VC / Q','TC × Q'],'correctIndex':0,"explanation":"AC = TC / Quantity."},
{"subject":"Economics",'year':2011,"question":"Marginal cost (MC) is the:",'options':['Change in total cost from producing one more unit','Total cost divided by output','Average cost','Fixed cost'],'correctIndex':0,"explanation":"MC = ΔTC / ΔQ."},
{"subject":"Economics",'year':2012,"question":"In the short run, if MC is below AC, then AC is:",'options':['Falling','Rising','Constant','Zero'],'correctIndex':0,"explanation":"MC pulls AC down."},
{"subject":"Economics",'year':2013,"question":"In the short run, if MC is above AC, then AC is:",'options':['Rising','Falling','Constant','Zero'],'correctIndex':0,"explanation":"MC pulls AC up."},
{"subject":"Economics",'year':2014,"question":"Economies of scale occur when:",'options':['Long-run average cost falls as output increases','Short-run average cost falls','Total cost falls','Marginal cost rises'],'correctIndex':0,"explanation":"Economies of scale are a long-run phenomenon."},
{"subject":"Economics",'year':2015,"question":"Diseconomies of scale occur when:",'options':['Long-run average cost rises as output increases','Long-run average cost falls','Short-run average cost falls','Total cost falls'],'correctIndex':0,"explanation":"Diseconomies arise from management and coordination problems."},
{"subject":"Economics",'year':2016,"question":"Internal economies of scale are:",'options':['Benefits from expansion within the firm','Benefits from expansion of the industry','External benefits','Government subsidies'],'correctIndex':0,"explanation":"Internal economies are firm-specific."},
{"subject":"Economics",'year':2017,"question":"External economies of scale are:",'options':['Benefits from expansion of the industry as a whole','Firm-specific benefits','Benefits from government policy','Benefits from trade'],'correctIndex':0,"explanation":"External economies arise from the industry"s growth.'},
{"subject":"Economics",'year':2018,"question":"Revenue is:",'options':['Total income from sales','Total cost','Profit','Investment'],'correctIndex':0,"explanation":"Revenue = Price × Quantity."},
{"subject":"Economics",'year':2019,"question":"Total revenue (TR) =:",'options':['Price × Quantity','Average revenue × Quantity','Both A and B','Price / Quantity'],'correctIndex':2,"explanation":"TR = P × Q = AR × Q."},
{"subject":"Economics",'year':2020,"question":"Average revenue (AR) =:",'options':['TR / Q','Price','Both A and B','MR'],'correctIndex':2,"explanation":"AR is revenue per unit, which equals price under perfect competition."},
{"subject":"Economics",'year':2021,"question":"Marginal revenue (MR) is the:",'options':['Change in total revenue from selling one more unit','Total revenue divided by quantity','Average revenue','Price'],'correctIndex':0,"explanation":"MR = ΔTR / ΔQ."},
{"subject":"Economics",'year':2022,"question":"In perfect competition, MR is:",'options':['Equal to price (AR)','Greater than price','Less than price','Zero'],'correctIndex':0,"explanation":"For a price taker, MR = AR = Price."},
{"subject":"Economics",'year':2023,"question":"In monopoly, MR is:",'options':['Less than price','Equal to price','Greater than price','Zero'],'correctIndex':0,"explanation":"Monopolist faces a downward-sloping demand curve, so MR < Price."},
{"subject":"Economics",'year':2024,"question":"Profit maximisation occurs where:",'options':['MR = MC','MR > MC','MR < MC','MC = 0'],'correctIndex':0,"explanation":"MC = MR is the profit-maximising rule."},
{"subject":"Economics",'year':2025,"question":"Normal profit is:",'options':['Minimum profit required to keep a firm in business','Zero profit','Supernormal profit','Loss'],'correctIndex':0,"explanation":"Normal profit is included in opportunity cost."},
{"subject":"Economics",'year':2026,"question":"Supernormal profit is:",'options':['Profit above normal profit','Profit below normal profit','Zero profit','Economic loss'],'correctIndex':0,"explanation":"Supernormal profit is above the competitive level."},
{"subject":"Economics",'year':2000,"question":"A firm will shut down in the short run if:",'options':['Price is less than average variable cost (AVC)','Price is less than average total cost (ATC)','Price is less than average fixed cost (AFC)','Price is zero'],'correctIndex':0,"explanation":"If P < AVC, the firm cannot cover variable costs."},
{"subject":"Economics",'year':2001,"question":"A firm will shut down in the long run if:",'options':['Price is less than average total cost (ATC)','Price is less than AVC','Price is less than AFC','Price is zero'],'correctIndex':0,"explanation":"In the long run, all costs are variable; exit if P < ATC."},
{"subject":"Economics",'year':2002,"question":"The break-even point is where:",'options':['TR = TC (normal profit)','MR = MC','TR > TC','TR < TC'],'correctIndex':0,"explanation":"Break-even earns normal profit."},
{"subject":"Economics",'year':2003,"question":"The profit-maximising output for a perfectly competitive firm is where:",'options':['P = MC','P = MR','MC = MR','All of these'],'correctIndex':3,"explanation":"Under perfect competition, P = MR = MC at equilibrium."},
{"subject":"Economics",'year':2004,"question":"A perfectly competitive firm is a:",'options':['Price taker','Price maker','Market leader','Monopolist'],'correctIndex':0,"explanation":"Perfect competition: firms accept market price."},
{"subject":"Economics",'year':2005,"question":"A monopoly is a market with:",'options':['A single seller','Many sellers','Few sellers','Many buyers'],'correctIndex':0,"explanation":"Monopoly is one seller."},
{"subject":"Economics",'year':2006,"question":"A monopoly can earn supernormal profit in the:",'options':['Short run and long run','Short run only','Long run only','Neither'],'correctIndex':0,"explanation":"Barriers to entry protect monopoly profits."},
{"subject":"Economics",'year':2007,"question":"Price discrimination means:",'options':['Charging different prices to different customers for the same good','Charging the same price','Charging below cost','Charging above cost'],'correctIndex':0,"explanation":"Price discrimination exploits market segmentation."},
{"subject":"Economics",'year':2008,"question":"Conditions for price discrimination include:",'options':['Market segmentation, no resale, different elasticities','Same market, resale allowed','Perfect competition','Uniform elasticity'],'correctIndex':0,"explanation":"These are the standard conditions."},
{"subject":"Economics",'year':2009,"question":"A monopoly causes deadweight loss because:",'options':['Output is lower than the competitive level','Prices are lower','Output is higher','Costs are lower'],'correctIndex':0,"explanation":"Monopoly restricts output to raise price, causing inefficiency."},
{"subject":"Economics",'year':2010,"question":"Monopolistic competition is characterised by:",'options':['Many firms, differentiated products, easy entry','One firm, many barriers','Few firms, collusion','Homogeneous products'],'correctIndex':0,"explanation":"Monopolistic competition is between perfect competition and monopoly."},
{"subject":"Economics",'year':2011,"question":"Oligopoly is characterised by:",'options':['Few firms, interdependence, barriers to entry','Many firms, homogeneous products','One firm','No barriers'],'correctIndex':0,"explanation":"Oligopoly has strategic interaction."},
{"subject":"Economics",'year':2012,"question":"Collusion occurs when firms:",'options':['Cooperate to set prices or output','Compete aggressively','Enter a market','Exit a market'],'correctIndex':0,"explanation":"Collusion reduces competition."},
{"subject":"Economics",'year':2013,"question":"A cartel is:",'options':['A formal agreement to collude','A type of market structure','A government agency','A trade union'],'correctIndex':0,"explanation":"Cartels set prices and outputs jointly (e.g., OPEC)."},
{"subject":"Economics",'year':2014,"question":"The kinked demand curve model explains:",'options':['Price rigidity in oligopoly','Price discrimination','Perfect competition','Monopoly pricing'],'correctIndex':0,"explanation":"The kinked demand curve shows that firms are reluctant to change prices."},
{"subject":"Economics",'year':2015,"question":"A natural monopoly occurs when:",'options':['A single firm can supply the entire market at lowest cost','There are many firms','Entry is free','Products are homogeneous'],'correctIndex':0,"explanation":"Natural monopoly has large economies of scale."},
{"subject":"Economics",'year':2016,"question":"Public goods are:",'options':['Non-rivalrous and non-excludable','Rivalrous and excludable','Rivalrous and non-excludable','Non-rivalrous and excludable'],'correctIndex':0,"explanation":"Public goods (e.g., defence) have these characteristics."},
